namespace sv_8299b66ed2d74faf84b004aef0bdfc50.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse and notifies
/// subscribers when it changes.  Registered as Scoped so each Blazor Server
/// circuit (i.e. each browser tab / user) gets its own instance.
/// </summary>
public sealed class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    /// <summary>
    /// Raised after the warehouse selection changes.
    /// Subscribers must call <see cref="ComponentBase.InvokeAsync"/> themselves
    /// if they need to marshal back onto the render thread.
    /// </summary>
    public event Func<Task>? OnChange;

    public async Task SetWarehouseAsync(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        if (OnChange is not null) await OnChange.Invoke();
    }
}

namespace sv_8299b66ed2d74faf84b004aef0bdfc50.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts and broadcasts results to
/// all subscribed components.  Polling is reference-counted so it runs only
/// while at least one subscriber is active (e.g. the dashboard is visible).
/// </summary>
public sealed class InventoryAlertService : IDisposable
{
    private static readonly Random s_random = new();

    private readonly WarehouseStateService _warehouseState;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private int _lastLowStockCount;

    public int LastLowStockCount => _lastLowStockCount;

    /// <summary>
    /// Raised when fresh alert data is available.  All subscribed components
    /// receive the notification so they can re-render.
    /// </summary>
    public event Func<Task>? OnAlertDataChanged;

    public InventoryAlertService(WarehouseStateService warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += HandleWarehouseChangedAsync;
    }

    /// <summary>Simulates a database query – returns a random count 0-15.</summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(s_random.Next(0, 16));
    }

    /// <summary>
    /// Starts (or joins) the polling loop.  Call <see cref="StopPolling"/> when
    /// the subscriber is removed / disposed.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _ = PollLoopAsync(_cts.Token);
        }
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _cts?.Dispose();
            _cts = null;
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        // Fetch immediately on start, then every 10 s.
        await FetchAndNotifyAsync();
        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await FetchAndNotifyAsync();
            }
        }
        catch (OperationCanceledException) { /* expected on stop */ }
    }

    private async Task FetchAndNotifyAsync()
    {
        _lastLowStockCount = await GetLowStockCountAsync(_warehouseState.CurrentWarehouseId);
        if (OnAlertDataChanged is not null) await OnAlertDataChanged.Invoke();
    }

    private async Task HandleWarehouseChangedAsync()
    {
        if (_subscriberCount > 0)
            await FetchAndNotifyAsync();
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= HandleWarehouseChangedAsync;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

