@page "/dashboard"
@using sv_8299b66ed2d74faf84b004aef0bdfc50.Services
@rendermode InteractiveServer
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Viewing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(_lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(_lowStockCount > 0 ? "text-danger" : "text-success")">
                    @_lowStockCount
                </p>
                <p class="text-muted small">
                    Items below minimum level &bull; refreshes every 10 s
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    private int _lowStockCount;

    protected override void OnInitialized()
    {
        _lowStockCount = AlertService.LastLowStockCount;
        AlertService.OnAlertDataChanged += HandleAlertDataChanged;
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.StartPolling();
    }

    private async Task HandleAlertDataChanged()
    {
        _lowStockCount = AlertService.LastLowStockCount;
        await InvokeAsync(StateHasChanged);
    }

    private async Task HandleWarehouseChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.StopPolling();
        AlertService.OnAlertDataChanged -= HandleAlertDataChanged;
        WarehouseState.OnChange -= HandleWarehouseChanged;
    }
}

